{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOlgWLv1yrYxhbd7RvbirOG"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"colab":{"base_uri":"https://localhost:8080/","height":364},"id":"okloEm3dBC-8","outputId":"36f755da-cc4e-4d80-988c-9342c2fa3de9"},"outputs":[{"output_type":"display_data","data":{"text/plain":["<IPython.core.display.HTML object>"],"text/html":["\n","    <div style=\"font-family:Arial;background:#eef2f7;padding:20px\">\n","        <h1 style=\"color:#1f4e79;\">🏥 Dashboard</h1>\n","        <div style=\"background:white;padding:20px;border-radius:12px;\n","                    box-shadow:0 4px 10px rgba(0,0,0,0.1);\">\n","            \n","        <h3>Welcome, admin</h3>\n","        <p>Select an option:</p>\n","        <b>1</b> ➜ Add Patient<br>\n","        <b>2</b> ➜ View Queue<br>\n","        <b>3</b> ➜ Complete Patient<br>\n","        <b>4</b> ➜ Search Patient<br>\n","        <b>5</b> ➜ Analytics<br>\n","        <b>6</b> ➜ Logout\n","        \n","        </div>\n","    </div>\n","    "]},"metadata":{}}],"source":["# ==============================\n","# 🏥 FINAL LEVEL 2 HOSPITAL QUEUE SYSTEM (ERROR-FREE)\n","# ==============================\n","\n","import pandas as pd\n","import time\n","import os\n","import matplotlib.pyplot as plt\n","from IPython.display import display, HTML, clear_output\n","\n","# ==============================\n","# 📁 FILE SETUP\n","# ==============================\n","FILE = \"patients.csv\"\n","\n","if not os.path.exists(FILE):\n","    df_init = pd.DataFrame(columns=[\"Token\",\"Name\",\"Priority\",\"Time\"])\n","    df_init.to_csv(FILE, index=False)\n","\n","# ==============================\n","# 🔐 USERS\n","# ==============================\n","users = {\n","    \"admin\": \"admin123\",\n","    \"reception\": \"1234\"\n","}\n","\n","# ==============================\n","# 🎨 UI FUNCTION\n","# ==============================\n","def ui(title, body):\n","    clear_output(wait=True)\n","    display(HTML(f\"\"\"\n","    <div style=\"font-family:Arial;background:#eef2f7;padding:20px\">\n","        <h1 style=\"color:#1f4e79;\">🏥 {title}</h1>\n","        <div style=\"background:white;padding:20px;border-radius:12px;\n","                    box-shadow:0 4px 10px rgba(0,0,0,0.1);\">\n","            {body}\n","        </div>\n","    </div>\n","    \"\"\"))\n","\n","# ==============================\n","# 📥 LOAD DATA SAFE\n","# ==============================\n","def load_data():\n","    try:\n","        df = pd.read_csv(FILE)\n","        return df\n","    except:\n","        return pd.DataFrame(columns=[\"Token\",\"Name\",\"Priority\",\"Time\"])\n","\n","# ==============================\n","# 💾 SAVE DATA\n","# ==============================\n","def save_data(df):\n","    df.to_csv(FILE, index=False)\n","\n","# ==============================\n","# 🔐 LOGIN\n","# ==============================\n","def login():\n","    while True:\n","        ui(\"Login\", \"<h3>Enter credentials below</h3>\")\n","        u = input(\"Username: \")\n","        p = input(\"Password: \")\n","\n","        if u in users and users[u] == p:\n","            dashboard(u)\n","            break\n","        else:\n","            print(\"❌ Invalid credentials\")\n","            time.sleep(1)\n","\n","# ==============================\n","# 📊 DASHBOARD\n","# ==============================\n","def dashboard(user):\n","    while True:\n","        ui(\"Dashboard\", f\"\"\"\n","        <h3>Welcome, {user}</h3>\n","        <p>Select an option:</p>\n","        <b>1</b> ➜ Add Patient<br>\n","        <b>2</b> ➜ View Queue<br>\n","        <b>3</b> ➜ Complete Patient<br>\n","        <b>4</b> ➜ Search Patient<br>\n","        <b>5</b> ➜ Analytics<br>\n","        <b>6</b> ➜ Logout\n","        \"\"\")\n","\n","        choice = input(\"Enter choice: \").strip()\n","\n","        if choice == \"1\":\n","            add_patient()\n","        elif choice == \"2\":\n","            view_queue()\n","        elif choice == \"3\":\n","            complete_patient()\n","        elif choice == \"4\":\n","            search_patient()\n","        elif choice == \"5\":\n","            analytics()\n","        elif choice == \"6\":\n","            break\n","        else:\n","            print(\"❌ Invalid choice\")\n","            time.sleep(1)\n","\n","# ==============================\n","# ➕ ADD PATIENT\n","# ==============================\n","def add_patient():\n","    df = load_data()\n","\n","    name = input(\"Patient Name: \").strip()\n","    priority = input(\"Priority (Emergency/Normal): \").strip().capitalize()\n","\n","    if priority not in [\"Emergency\", \"Normal\"]:\n","        print(\"❌ Invalid priority\")\n","        time.sleep(1)\n","        return\n","\n","    token = 1 if df.empty else int(df[\"Token\"].max()) + 1\n","\n","    new_row = pd.DataFrame([{\n","        \"Token\": token,\n","        \"Name\": name,\n","        \"Priority\": priority,\n","        \"Time\": time.strftime(\"%H:%M:%S\")\n","    }])\n","\n","    df = pd.concat([df, new_row], ignore_index=True)\n","\n","    # Priority sorting\n","    df[\"Sort\"] = df[\"Priority\"].apply(lambda x: 0 if x == \"Emergency\" else 1)\n","    df = df.sort_values(by=[\"Sort\", \"Token\"]).drop(columns=[\"Sort\"])\n","\n","    save_data(df)\n","\n","    print(f\"✅ Patient added! Token: {token}\")\n","    time.sleep(1)\n","\n","# ==============================\n","# 📋 VIEW QUEUE\n","# ==============================\n","def view_queue():\n","    df = load_data()\n","\n","    if df.empty:\n","        print(\"⚠️ No patients in queue\")\n","    else:\n","        df = df.copy()\n","        avg_time = 5\n","        df[\"Waiting(min)\"] = [i * avg_time for i in range(len(df))]\n","        display(df)\n","\n","    input(\"Press Enter to continue...\")\n","\n","# ==============================\n","# ✔️ COMPLETE PATIENT\n","# ==============================\n","def complete_patient():\n","    df = load_data()\n","\n","    if df.empty:\n","        print(\"⚠️ No patients\")\n","        time.sleep(1)\n","        return\n","\n","    display(df)\n","\n","    try:\n","        token = int(input(\"Enter Token to complete: \"))\n","        if token in df[\"Token\"].values:\n","            df = df[df[\"Token\"] != token]\n","            save_data(df)\n","            print(\"✅ Patient completed\")\n","        else:\n","            print(\"❌ Token not found\")\n","    except:\n","        print(\"❌ Invalid input\")\n","\n","    time.sleep(1)\n","\n","# ==============================\n","# 🔍 SEARCH\n","# ==============================\n","def search_patient():\n","    df = load_data()\n","\n","    name = input(\"Enter patient name: \").strip()\n","\n","    result = df[df[\"Name\"].str.contains(name, case=False, na=False)]\n","\n","    if result.empty:\n","        print(\"❌ No matching patient\")\n","    else:\n","        display(result)\n","\n","    input(\"Press Enter to continue...\")\n","\n","# ==============================\n","# 📊 ANALYTICS\n","# ==============================\n","def analytics():\n","    df = load_data()\n","\n","    if df.empty:\n","        print(\"⚠️ No data available\")\n","        time.sleep(1)\n","        return\n","\n","    counts = df[\"Priority\"].value_counts()\n","\n","    plt.figure()\n","    counts.plot(kind=\"bar\")\n","    plt.title(\"Patient Priority Distribution\")\n","    plt.xlabel(\"Priority\")\n","    plt.ylabel(\"Count\")\n","    plt.show()\n","\n","    input(\"Press Enter to continue...\")\n","\n","# ==============================\n","# 🚀 START SYSTEM\n","# ==============================\n","login()"]}]}